import{_ as a,o as i,c as s,ag as c}from"./chunks/framework.CAXxHpAX.js";const y=JSON.parse('{"title":"中共十一届三中全会：","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-32.md","filePath":"notes/note-32.md"}'),l={name:"notes/note-32.md"};function v(r,d,e,o,t,n){return i(),s("div",null,[...d[0]||(d[0]=[c('<h1 id="中共十一届三中全会" tabindex="-1">中共十一届三中全会： <a class="header-anchor" href="#中共十一届三中全会" aria-label="Permalink to &quot;中共十一届三中全会：&quot;">​</a></h1><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">中共十一届三中全会：</span></p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>①是新中国成立以来党和国家历史上具有深远意义的伟大转折，开启了改革开放和社会主义现代化建设的新时期。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>②形成以邓小平为核心的第二代中央领导集体。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">农村经济体制改革内容：</span>1978年，家庭联产承包责任制、分田包干到户、自负盈亏</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">作用：</span></p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>①农民有了生产自主权，激发农民的劳动热情，生产积极性提高，带来了农村生产力解放，农业生产和农民收入均有很大提高；</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>②农业生产向专业化、商品化、社会化发展，推动农村乡镇企业发展，为农民致富和实现现代化开辟了一条新路。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">城市经济体制改革：</span>1984年，中心环节：增强企业活力。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">城市经济体制改革的意义：</span>企业有了经营自主权；大大调动了企业、职工的积极性，增强了企业的活力。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">经济特区：</span>1980年，深圳（窗口）、珠海、汕头、厦门。1984年，广州沿海开放城市。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">经济特区的作用：</span>引进外资、先进技术和管理经验，推动国内的进一步改革，扩大对外经济交流，发展社会主义现代化事业起到重要作用。</p></div><div class="circle-overlay"></div></div></div>',12)])])}const b=a(l,[["render",v]]);export{y as __pageData,b as default};
